106	/* Warning: the register must be at top of stack */
107	static void free_expreg(bfuncinfo *finfo, bexpdesc *e)
108	{
109	    /* release temporary register */
110	    if (e && e->type == ETREG) {
111	        be_code_freeregs(finfo, 1);
112	    }
