518	void be_code_prebinop(bfuncinfo *finfo, int op, bexpdesc *e)
519	{
520	    switch (op) {
521	    case OptAnd:
522	        be_code_jumpbool(finfo, e, bfalse);
523	        break;
524	    case OptOr:
525	        be_code_jumpbool(finfo, e, btrue);
526	        break;
527	    default:
528	        exp2anyreg(finfo, e);
529	        break;
530	    }
531	}
