569	/* Apply not to conditional expression */
570	/* If literal compute the value */
571	/* Or invert t/f subexpressions */
572	static void code_not(bexpdesc *e)
573	{
574	    switch (e->type) {
575	    case ETINT: e->v.i = e->v.i == 0; break;
576	    case ETREAL: e->v.i = e->v.r == cast(breal, 0); break;
577	    case ETNIL: e->v.i = 1; break;
578	    case ETBOOL: e->v.i = !e->v.i; break;
579	    case ETSTRING: e->v.i = 0; break;
580	    default: {
581	        int temp = e->t;
582	        e->t = e->f;
583	        e->f = temp;
584	        e->not = NOT_EXPR | (e->not ^ NOT_MASK);
585	        return;
586	    }
587	    }
588	    e->type = ETBOOL;
589	}
590	
591	/* Negative value of literal or emit NEG opcode */
592	static int code_neg(bfuncinfo *finfo, bexpdesc *e)
593	{
594	    switch (e->type) {
595	    case ETINT: e->v.i = -e->v.i; break;
596	    case ETREAL: e->v.r = -e->v.r; break;
597	    case ETNIL: case ETBOOL: case ETSTRING:
598	        return 1; /* error */
599	    default:
600	        unaryexp(finfo, OP_NEG, e);
601	    }
602	    return 0;
603	}
604	
605	/* Bit flip of literal or emit FLIP opcode */
606	static int code_flip(bfuncinfo *finfo, bexpdesc *e)
607	{
608	    switch (e->type) {
609	    case ETINT: e->v.i = ~e->v.i; break;
610	    case ETREAL: case ETNIL: case ETBOOL: case ETSTRING:
611	        return 2; /* error */
612	    default:
613	        unaryexp(finfo, OP_FLIP, e);
614	    }
615	    return 0;
616	}
617	
618	/* Apply unary operator: not, neg or bitflip */
619	int be_code_unop(bfuncinfo *finfo, int op, bexpdesc *e)
620	{
621	    switch (op) {
622	    case OptNot:
623	        code_not(e); break;
624	    case OptFlip: /* do nothing */
625	        return code_flip(finfo, e);
626	    case OptSub:
627	        return code_neg(finfo, e);
628	    default:
629	        break;
630	    }
631	    return 0;
632	}
