702	/* Get the expdesc as a register */
703	/* if already in a register, use the existing register */
704	/* if local or const, allocate a new register and copy value */
705	int be_code_nextreg(bfuncinfo *finfo, bexpdesc *e)
706	{
707	    int dst = finfo->freereg;
708	    int src = exp2anyreg(finfo, e); /* get variable register index */
709	    if (e->type != ETREG) { /* move local and const to new register */
710	        code_move(finfo, dst, src);
711	        be_code_allocregs(finfo, 1);
712	    } else {
713	        dst = src;
714	    }
715	    return dst;
716	}
